mapper.select:
SELECT id, email, nickname, profile_img, provider, created_at
FROM `USER`
WHERE id = #{id}

SELECT id, email, password, nickname, profile_img, provider, provider_id, created_at
FROM `USER`
WHERE email = #{email}

SELECT COUNT(*) > 0
FROM `USER`
WHERE email = #{email}
  AND id != #{id}

SELECT COUNT(*) > 0
FROM `USER`
WHERE nickname = #{nickname}
  AND id != #{id}

